#include <bits/stdc++.h>
using namespace std;
long long a[1005],l;
int main(){
	int n;
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[i];
	}
	for(int i=0;i<n;i++){
		for(int j=i+1;j<n;j++){
			if(sqrt(a[i]+a[j])==int(sqrt(a[i]+a[j]))){
				l++;
			}
		}
	}
	cout<<l;
	return 0;
}
